"use client";

import Image from "next/image";

interface HeroImageProps {
	src: string;
	alt: string;
	height?: number;
	width?: number;
	className?: string;
}

const HeroImage: React.FC<HeroImageProps> = ({
	src,
	alt,
	height = 720,
	width = 1280,
	className = "",
}) => {
	return (
		<div className="mx-auto mt-8 w-full shadow-lg">
			<Image
				src={src}
				alt={alt}
				height={height}
				width={width}
				priority={true}
				quality={100}
				placeholder="blur"
				sizes="(max-width: 768px) 100vw, (max-width: 1200px) 100vw, 70vw"
				className={`aspect-auto w-full overflow-hidden rounded-xl object-cover object-center ${className}`}
				blurDataURL="data:image/jpeg;base64,"
			/>
		</div>
	);
};

export default HeroImage;
